local _b64 = table.concat(_b64Parts)

local function exec()
    local dec = nil
    if type(crypt) == "table" and type(crypt.base64decode) == "function" then
        pcall(function() dec = crypt.base64decode(_b64) end)
    elseif type(crypt) == "table" and type(crypt.base64_decode) == "function" then
        pcall(function() dec = crypt.base64_decode(_b64) end)
    elseif type(base64_decode) == "function" then
        pcall(function() dec = base64_decode(_b64) end)
    elseif type(base64decode) == "function" then
        pcall(function() dec = base64decode(_b64) end)
    end
    
    if not dec then
        -- Native pure Lua fallback
        local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
        local t = {}
        for i=1,64 do t[b:sub(i,i)] = i-1 end
        local res = {}
        local data = string.gsub(_b64, '[^'..b..'=]', '')
        local len = #data
        for i = 1, len, 4 do
            local n = (t[data:sub(i,i)] or 0)*262144 + (t[data:sub(i+1,i+1)] or 0)*4096 + (t[data:sub(i+2,i+2)] or 0)*64 + (t[data:sub(i+3,i+3)] or 0)
            local b1 = math.floor(n/65536)
            local b2 = math.floor((n/256)%256)
            local b3 = n%256
            if data:sub(i+2,i+2) == '=' then
                res[#res+1] = string.char(b1)
            elseif data:sub(i+3,i+3) == '=' then
                res[#res+1] = string.char(b1, b2)
            else
                res[#res+1] = string.char(b1, b2, b3)
            end
        end
        dec = table.concat(res)
    end

    local _TL_OBF_HDR = "--[TL-OBF]\n"
    local function _TL_deobf(d)
        if typeof(d) ~= "string" or d:sub(1, #_TL_OBF_HDR) ~= _TL_OBF_HDR then return d end
        local b = d:sub(#_TL_OBF_HDR + 1):reverse()
        local r = {}
        for i = 1, #b do r[i] = string.char((b:byte(i) - 42) % 256) end
        return table.concat(r)
    end

    local src = _TL_deobf(dec)
    
    -- Strip BOM just in case it's still there
    if src:sub(1,3) == string.char(239, 187, 191) then
        src = src:sub(4)
    end

    local fn, err = loadstring(src)
    if fn then
        fn()
    else
        warn("TLMenu Failed to load: " .. tostring(err))
    end
end

exec()
